Now I have a comprehensive view of the OpenCore coredump implementation. Let me provide a detailed analysis.

---

## OpenCore 深度分析

### 1. 信号处理机制 (HandleSignal)

**位置**: `opencore.cpp:64-70`

```cpp
void Opencore::HandleSignal(int signal, siginfo_t* siginfo, void* ucontext_raw) {
    pthread_mutex_lock(&g_handle_lock);
    Disable();
    Dump(siginfo, ucontext_raw);
    raise(signal);
    pthread_mutex_unlock(&g_handle_lock);
}
```

**处理流程**:
1. 获取全局锁 `g_handle_lock`（防止并发）
2. 调用 `Disable()` 卸载信号处理器
3. 调用 `Dump()` 执行 coredump
4. `raise(signal)` 重新抛出信号让默认处理器处理
5. 解锁并退出

**处理的异常信号** (第57-60行):
```cpp
static constexpr int kExceptionSignals[] = {
    SIGSEGV, SIGABRT, SIGFPE, SIGILL, SIGBUS, SIGTRAP
};
```

---

### 2. 线程停止机制 (StopTheWorld)

**StopTheWorld** (`opencore.cpp:443-459`):
```cpp
void Opencore::StopTheWorld(int pid) {
    char task_dir[32];
    struct dirent *entry;
    snprintf(task_dir, sizeof(task_dir), "/proc/%d/task", pid);
    DIR *dp = opendir(task_dir);
    if (dp) {
        while ((entry=readdir(dp)) != NULL) {
            if (!strncmp(entry->d_name, ".", 1)) continue;
            pid_t tid = std::atoi(entry->d_name);
            Opencore::StopTheThread(tid);
        }
        closedir(dp);
    }
}
```

**StopTheThread** (`opencore.cpp:461-491`):
```cpp
bool Opencore::StopTheThread(int tid) {
    ThreadRecord ts = { .pid = tid, .attached = false };
    if (ptrace(PTRACE_ATTACH, tid, NULL, 0) < 0) {
        threads.push_back(ts);
        return false;
    }
    ts.attached = true;
    threads.push_back(ts);

    int status = 0;
    int result = waitpid(tid, &status, WUNTRACED | __WALL);
    if (result != tid) return false;
    if (WIFSTOPPED(status)) {
        int received_signal = (status >> 16 == PTRACE_EVENT_STOP) ? 0 : WSTOPSIG(status);
        return true;
    }
    return false;
}
```

**Continue** (`opencore.cpp:493-504`):
```cpp
void Opencore::Continue() {
    for (int index = 0; index < threads.size(); index++) {
        ThreadRecord& ts = threads[index];
        if (!ts.attached) continue;
        pid_t tid = ts.pid;
        if (ptrace(PTRACE_DETACH, tid, NULL, 0) < 0) continue;
    }
    threads.clear();
}
```

**算法**:
1. 遍历 `/proc/<pid>/task` 获取所有线程 TID
2. 对每个线程执行 `PTRACE_ATTACH`
3. `waitpid(tid, &status, WUNTRACED | __WALL)` 等待线程停止
4. 恢复时使用 `PTRACE_DETACH` 分离线程

---

### 3. VMA 过滤逻辑 (IsFilterSegment)

**位置**: `opencore.cpp:397-441`

```cpp
int Opencore::IsFilterSegment(Opencore::VirtualMemoryArea& vma) {
    int filter = getFilter();

    // 1. 特殊设备过滤
    if (filter & FILTER_SPECIAL_VMA) {
        if (vma.file == "/dev/binderfs/hwbinder"
                || vma.file == "/dev/binderfs/binder"
                || vma.file == "[vvar]"
                || vma.file == "/dev/mali0")
            return VMA_NULL;
    }

    // 2. 文件VMA过滤 (inode > 0 且不是匿名映射)
    if (filter & FILTER_FILE_VMA) {
        if (vma.inode > 0 && vma.flags[1] == '-')
            return NeedFilterFile(vma);
    }

    // 3. 共享VMA过滤 (flags[3] == 's'/'S')
    if (filter & FILTER_SHARED_VMA) {
        if (vma.flags[3] == 's' || vma.flags[3] == 'S')
            return VMA_NULL;
    }

    // 4. Sanitizer shadow memory
    if (filter & FILTER_SANITIZER_SHADOW_VMA) {
        if (vma.file == "[anon:low shadow]"
                || vma.file == "[anon:high shadow]"
                || (vma.file.compare(0, 12, "[anon:hwasan") == 0))
            return VMA_NULL;
    }

    // 5. 不可读VMA过滤
    if (filter & FILTER_NON_READ_VMA) {
        if (vma.flags[0] == '-' && vma.flags[1] == '-' && vma.flags[2] == '-')
            return VMA_NULL;
    }

    // 6. Dalvik Java堆
    if (filter & FILTER_JAVAHEAP_VMA) {
        if (vma.file.compare(0, 12, "[anon:dalvik") == 0)
            return VMA_NULL;
    }

    // 7. JIT Cache
    if (filter & FILTER_JIT_CACHE_VMA) {
        if (vma.file.compare(0, 10, "/memfd:jit") == 0)
            return VMA_NULL;
    }
    return VMA_NORMAL;
}
```

**ARM64 专用过滤** (`arm64/opencore.cpp:118-164`):
```cpp
int Opencore::IsSpecialFilterSegment(Opencore::VirtualMemoryArea& vma) {
    if (filter & FILTER_MINIDUMP) {
        arm64::pt_regs *regs = &prstatus[0].pr_reg;
        // 检查 PC 和所有通用寄存器是否落在 VMA 范围内
        if (regs->pc >= vma.begin && regs->pc < vma.end
                || regs->regs[0] >= vma.begin && regs->regs[0] < vma.end
                // ... regs[1] 到 regs[30] 和 sp
                || regs->sp >= vma.begin && regs->sp < vma.end) {
            return VMA_INCLUDE;  // 包含此 VMA
        }
        return VMA_NULL;
    }
    return VMA_NORMAL;
}
```

**FILTER_MINIDUMP 模式**: 只保留寄存器引用的内存区域，实现最小化 dump。

---

### 4. Dump 流程 (DoCoredump)

**核心流程** (`lp64/opencore.cpp:285-321`):

```cpp
bool OpencoreImpl::DoCoredump(const char* filename) {
    Prepare(filename);
    FILE* fp = fopen(filename, "wb");

    StopTheWorld(getPid());              // 1. 停止所有线程
    ParseProcessMapsVma(getPid());      // 2. 解析 /proc/<pid>/maps
    CreateCoreHeader();                  // 3. 创建 ELF Header
    CreateCoreNoteHeader();             // 4. 创建 Note Segment Header
    CreateCorePrStatus(getPid());       // 5. 创建线程寄存器状态
    CreateCoreAUXV(getPid());           // 6. 读取 AUXV
    SpecialCoreFilter();                // 7. 应用 VMA 过滤器

    // 写入 ELF 结构
    WriteCoreHeader(fp);               // ELF Header
    WriteCoreNoteHeader(fp);           // PT_NOTE Header
    WriteCoreProgramHeaders(fp);        // Program Headers (PT_LOAD)

    // 写入 Note 数据
    WriteCorePrStatus(fp);             // NT_PRSTATUS (每线程)
    WriteCoreAUXV(fp);                 // NT_AUXV
    WriteNtFile(fp);                    // NT_FILE (文件映射信息)
    AlignNoteSegment(fp);              // 对齐填充
    WriteCoreLoadSegment(getPid(), fp); // 实际内存内容 (PT_LOAD)

    fflush(fp);
    fsync(fileno(fp));
    fclose(fp);
    return true;
}
```

